import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "get_top_markets",
    args: {
      sortBy: "volume",
      category: "sports",
      minLiquidity: 25000,
      limit: 8
    }
  });

  let markets = Array.isArray(result?.markets) ? result.markets : [];

  if (markets.length < 8) {
    const fallback = await callMcpSkill({
      toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
      toolName: "get_top_markets",
      args: {
        sortBy: "volume",
        category: "sports",
        minLiquidity: 0,
        limit: 8
      }
    });

    const combined = [...markets, ...(Array.isArray(fallback?.markets) ? fallback.markets : [])];
    const seen = new Set();
    markets = combined.filter((m) => {
      const key = m?.conditionId || m?.slug || m?.url || m?.title;
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    }).slice(0, 8);
  }

  return {
    markets: markets.map((m) => ({
      title: m.title,
      currentPrice: m.currentPrice,
      volume24h: m.volume24h,
      liquidity: m.liquidity,
      url: m.url
    }))
  };
}

